import { useState, useEffect, useMemo, useCallback } from "react";
import { Link, useSearchParams } from "react-router-dom";
import { Search, AlertTriangle, Store, MapPin, Warehouse, ArrowLeft, RefreshCw, Package, ChevronDown, ChevronUp } from "lucide-react";
import { motion } from "framer-motion";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import BackToTop from "@/components/landing/BackToTop";
import { Reveal } from "@/components/landing/motion";
import { fetchChestShops, fetchWarpZones } from "@/lib/castiaClient";
import { fmt } from "@/lib/parseItem";

const PAGE_SIZE = 50;

export default function ShopsPage() {
  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [searchParams, setSearchParams] = useSearchParams();
  const [q, setQ] = useState(() => searchParams.get("item") || "");
  const [page, setPage] = useState(1);
  const [zones, setZones] = useState([]);
  const [warpFilter, setWarpFilter] = useState("");
  const [sortKey, setSortKey] = useState("");
  const [sortDir, setSortDir] = useState("asc");

  useEffect(() => {
    if (searchParams.has("item")) {
      const next = new URLSearchParams(searchParams);
      next.delete("item");
      setSearchParams(next, { replace: true });
    }
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const doFetch = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const [shopData, zoneData] = await Promise.all([
        fetchChestShops({ limit: 200 }),
        fetchWarpZones({ limit: 500 }).catch(() => ({ zones: [] })),
      ]);
      setRows(Array.isArray(shopData) ? shopData : shopData?.rows || shopData?.shops || []);
      setZones(Array.isArray(zoneData) ? zoneData : zoneData?.zones || []);
    } catch (e) {
      setError(e.message || "Failed to load chest shops");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { doFetch(); }, [doFetch]);

  const query = q.trim().toLowerCase();
  const matchShopToZone = useCallback((shop, zoneList) => {
    if (!shop || !zoneList?.length) return null;
    for (const z of zoneList) {
      if (z.dimensionKey !== shop.dimensionKey) continue;
      if (z.serverKey !== shop.serverKey) continue;
      const dx = (shop.x || 0) - (z.centerX || 0);
      const dy = (shop.y || 0) - (z.centerY || 0);
      const dz = (shop.z || 0) - (z.centerZ || 0);
      const dist = Math.sqrt(dx * dx + dy * dy + dz * dz);
      if (dist <= (z.radius || 256)) return z.warpName;
    }
    return null;
  }, []);

  const rowsWithWarps = useMemo(() => {
    return rows.map((r) => ({
      ...r,
      warpName: r.warpName || matchShopToZone(r, zones) || null,
    }));
  }, [rows, zones, matchShopToZone]);

  const zoneNames = useMemo(() => {
    const names = new Set();
    rowsWithWarps.forEach((r) => { if (r.warpName) names.add(r.warpName); });
    return Array.from(names).sort();
  }, [rowsWithWarps]);

  const filtered = useMemo(() => {
    let f = rowsWithWarps;
    if (query) {
      f = f.filter((r) => {
        const item = (r.itemName || r.itemTag || "").toLowerCase();
        const seller = (r.seller || "").toLowerCase();
        return item.includes(query) || seller.includes(query);
      });
    }
    if (warpFilter) {
      f = f.filter((r) => r.warpName === warpFilter);
    }
    if (sortKey === "price") {
      f.sort((a, b) => sortDir === "asc" ? a.unitPrice - b.unitPrice : b.unitPrice - a.unitPrice);
    } else if (sortKey === "stock") {
      f.sort((a, b) => sortDir === "asc" ? (a.stockCount||0) - (b.stockCount||0) : (b.stockCount||0) - (a.stockCount||0));
    } else if (sortKey === "freshness") {
      f.sort((a, b) => {
        const ta = a.lastSeenAt ? new Date(a.lastSeenAt).getTime() : 0;
        const tb = b.lastSeenAt ? new Date(b.lastSeenAt).getTime() : 0;
        return sortDir === "asc" ? ta - tb : tb - ta;
      });
    }
    return f;
  }, [rowsWithWarps, query, warpFilter, sortKey, sortDir]);

  const totalPages = Math.max(1, Math.ceil(filtered.length / PAGE_SIZE));
  const safePage = Math.min(page, totalPages);
  const visible = useMemo(() => {
    const start = (safePage - 1) * PAGE_SIZE;
    return filtered.slice(start, start + PAGE_SIZE);
  }, [filtered, safePage]);

  useEffect(() => { setPage(1); }, [query, warpFilter, sortKey, sortDir]);

  const locStr = (r) => {
    const parts = [];
    if (r.dimensionKey) parts.push(r.dimensionKey.replace(/_/g, " "));
    if (r.x != null && r.y != null && r.z != null) parts.push(`(${r.x}, ${r.y}, ${r.z})`);
    return parts.join(" ") || "\u2014";
  };

  return (
    <div data-testid="shops-page" className="min-h-screen bg-bg-base text-white font-body">
      <Header />
      <main className="pt-32 pb-24">
        <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
          <Reveal>
            <Link
              to="/listings"
              className="inline-flex items-center gap-1 text-zinc-500 hover:text-emerald-400 font-mono text-[10px] uppercase tracking-[0.2em] mb-4 transition-colors"
            >
              <ArrowLeft className="w-3 h-3" /> Back to listings
            </Link>
            <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-indigo-400 mb-4 inline-flex items-center gap-2">
              <Store className="w-3 h-3" /> / Shops
            </div>
            <h1 className="font-heading text-5xl sm:text-6xl lg:text-7xl tracking-tighter font-black leading-[0.95]">
              Chest <span className="text-indigo-400">Shops</span>
            </h1>
            <p className="mt-6 text-zinc-400 max-w-2xl text-lg">
              Browse chest-shop listings across the server. Each entry shows the seller, stock, price, and physical location.
            </p>
          </Reveal>

          {/* Search + refresh */}
          <Reveal delay={0.05} className="mt-10">
            <div className="flex items-center gap-3 flex-wrap">
              <div className="relative flex-1 min-w-[140px] sm:min-w-[200px] max-w-sm">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500 pointer-events-none" />
                <input
                  data-testid="shops-search"
                  aria-label="Search shops by item or seller name"
                  value={q}
                  onChange={(e) => setQ(e.target.value)}
                  placeholder="Search items or sellers\u2026"
                  className="w-full bg-white/[0.04] border border-white/10 rounded-sm pl-10 pr-4 py-2.5 text-sm text-white placeholder:text-zinc-600 focus:outline-none focus:border-indigo-500/50 transition-colors"
                />
              </div>
              <button
                onClick={doFetch}
                data-testid="shops-refresh"
                className="inline-flex items-center gap-2 border border-white/10 hover:border-white/30 text-zinc-300 hover:text-white font-bold uppercase tracking-[0.18em] text-[10px] px-4 py-2.5 rounded-sm transition-colors"
              >
                <RefreshCw className="w-3.5 h-3.5" /> Refresh
              </button>
              <select
                aria-label="Filter by warp zone"
                value={warpFilter}
                onChange={(e) => setWarpFilter(e.target.value)}
                className="bg-white/[0.04] border border-white/10 rounded-sm px-3 py-2.5 text-xs text-zinc-300 focus:outline-none focus:border-indigo-500/50 transition-colors uppercase tracking-wider"
              >
                <option value="">All zones</option>
                {zoneNames.map((name) => (
                  <option key={name} value={name} className="bg-bg-deep">{name}</option>
                ))}
              </select>
            </div>
          </Reveal>

          {/* Loading state */}
          {loading && (
            <div className="mt-10 space-y-3">
              {Array.from({ length: 8 }).map((_, i) => (
                <div key={i} className="h-14 bg-white/[0.02] rounded-sm animate-pulse" />
              ))}
            </div>
          )}

          {/* Error state */}
          {!loading && error && (
            <Reveal>
              <div data-testid="shops-error" className="mt-16 text-center max-w-md mx-auto">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-red-500/10 border border-red-500/30 mb-6">
                  <AlertTriangle className="w-7 h-7 text-red-400" />
                </div>
                <h2 className="font-heading text-2xl font-black mb-3">Failed to load shops</h2>
                <p className="text-zinc-400 text-sm leading-relaxed mb-6">{error}</p>
                <button
                  onClick={doFetch}
                  className="inline-flex items-center gap-2 bg-indigo-500 hover:bg-indigo-400 text-black font-bold uppercase tracking-[0.18em] text-xs px-5 py-3 rounded-sm transition-colors"
                >
                  <RefreshCw className="w-4 h-4" /> Retry
                </button>
              </div>
            </Reveal>
          )}

          {/* Empty state */}
          {!loading && !error && filtered.length === 0 && (
            <Reveal>
              <div data-testid="shops-empty" className="mt-16 text-center max-w-md mx-auto">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-indigo-500/10 border border-indigo-500/30 mb-6">
                  <Warehouse className="w-7 h-7 text-indigo-400" />
                </div>
                <h2 className="font-heading text-2xl font-black mb-3">No shops found</h2>
                <p className="text-zinc-400 text-sm leading-relaxed mb-6">
                  {query ? "Try a different search term." : "No chest shops are currently available."}
                </p>
              </div>
            </Reveal>
          )}

          {/* Table */}
          {!loading && !error && visible.length > 0 && (
            <Reveal delay={0.1} className="mt-8">
              <div className="text-xs text-zinc-500 mb-3 font-mono">{filtered.length} shop{filtered.length === 1 ? "" : "s"}{query ? ` matching "${q}"` : ""}</div>
              <div className="border border-white/10 rounded-2xl overflow-hidden">
                <div className="overflow-x-auto no-scrollbar">
                  <table className="w-full text-sm">
                    <thead>
                      <tr className="bg-white/[0.02] border-b border-white/10 text-left">
                        <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500">Item</th>
                        <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500">Seller</th>
                        <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 text-right">
                          <button
                            onClick={() => { setSortKey(sortKey === "stock" && sortDir === "asc" ? "" : "stock"); setSortDir("asc"); }}
                            className="inline-flex items-center gap-1 hover:text-white transition-colors"
                          >
                            Stock
                            {sortKey === "stock" ? (sortDir === "asc" ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />) : null}
                          </button>
                        </th>
                        <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 text-right">
                          <button
                            onClick={() => { if (sortKey === "price" && sortDir === "asc") { setSortKey(""); } else { setSortKey("price"); setSortDir("asc"); } }}
                            className="inline-flex items-center gap-1 hover:text-white transition-colors"
                          >
                            Price
                            {sortKey === "price" ? (sortDir === "asc" ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />) : null}
                          </button>
                        </th>
                        <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 hidden md:table-cell">Location</th>
                        <th className="px-4 py-3 font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 hidden md:table-cell">Warp</th>
                      </tr>
                    </thead>
                    <tbody>
                      {visible.map((r, i) => (
                        <motion.tr
                          key={`${r.seller}-${r.itemName || r.itemTag}-${r.x}-${r.y}-${r.z}`}
                          initial={{ opacity: 0 }}
                          animate={{ opacity: 1 }}
                          transition={{ delay: i * 0.012 }}
                          className="border-b border-white/5 last:border-0 hover:bg-white/[0.03] transition-colors"
                        >
                          <td className="px-4 py-3">
                            <span className="font-heading font-bold text-white">{r.itemName || r.itemTag || "\u2014"}</span>
                          </td>
                          <td className="px-4 py-3">
                            <span className="text-zinc-300">{r.seller || "\u2014"}</span>
                          </td>
                          <td className="px-4 py-3 text-right">
                            <span className="tabular inline-flex items-center gap-1 justify-end">
                              <Package className="w-3 h-3 text-zinc-500 shrink-0" />
                              {r.stockItemName ? `${r.stockCount ?? "?"}\u00d7 ${r.stockItemName}` : "\u2014"}
                            </span>
                          </td>
                          <td className="px-4 py-3 text-right">
                            <span className="font-mono tabular text-indigo-400 font-bold">{r.unitPrice > 0 ? fmt(r.unitPrice) : "\u2014"}</span>
                          </td>
                          <td className="px-4 py-3 hidden md:table-cell">
                            <span className="inline-flex items-center gap-1 text-zinc-400">
                              <MapPin className="w-3 h-3 text-zinc-500 shrink-0" />
                              {locStr(r)}
                            </span>
                          </td>
                          <td className="px-4 py-3 hidden md:table-cell">
                            <span className="text-zinc-400">{r.warpName || "\u2014"}</span>
                          </td>
                        </motion.tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>

              {/* Pagination */}
              {totalPages > 1 && (
                <div className="flex items-center justify-between mt-4 text-xs text-zinc-500">
                  <span className="font-mono">
                    Page {safePage} of {totalPages}
                  </span>
                  <div className="flex gap-2">
                    <button
                      disabled={safePage <= 1}
                      onClick={() => setPage((p) => Math.max(1, p - 1))}
                      className="px-3 py-1.5 border border-white/10 rounded-sm hover:border-white/30 disabled:opacity-30 disabled:pointer-events-none transition-colors font-mono text-[10px] uppercase tracking-wider"
                    >
                      Previous
                    </button>
                    <button
                      disabled={safePage >= totalPages}
                      onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
                      className="px-3 py-1.5 border border-white/10 rounded-sm hover:border-white/30 disabled:opacity-30 disabled:pointer-events-none transition-colors font-mono text-[10px] uppercase tracking-wider"
                    >
                      Next
                    </button>
                  </div>
                </div>
              )}
            </Reveal>
          )}
        </div>
      </main>
      <Footer />
      <BackToTop />
    </div>
  );
}
